(window.webpackJsonp=window.webpackJsonp||[]).push([[38],{665:function(n,t){n.exports='\x3c!-- \ntitle: 11-Linux杂\nsort: \n--\x3e \n\n## Curl\n\n发送网络请求\n\n```bash\ncurl https://www.baidu.com/\n# 下载\ncurl https://www.baidu.com/ -o 1.html\n# 静音模式，不输出任何东西\ncurl https://www.baidu.com/ -s \n# 指定请求头\ncurl -H -d -X\n# 设置头、post方法以及date\ncurl https://www.baidu.com/?name ==\'kiki\' -H "A:B" -X POST -d "age = 22"\n```\n\n## 后台执行\n\n```\n ./test &\n ./test >> out.txt 2>&1 &    # 将标准输出重定向到out.txt\n jobs -l     # 查看后台程序\n nohup ./test &  # 不挂起\n```\n\n## 信息\n\n```\n free -h     # 内存信息\n ps -ef | grep python3\n```'}}]);